import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should calculate premium for a single sword (base + first-insurance surcharge + processing fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should calculate premium for a single amulet", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it.todo("should calculate premium for a single staff");
    it.todo("should calculate premium for a single potion");
    it.todo("should calculate premium for a single component");
    it.todo("should sum premiums for multiple items in one quote");
    it.todo("should apply special 60G building block premium for 3 alike components");
    it.todo("should add 50% risk surcharge for cursed items");
    it.todo("should add 30% risk surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges on the same item");
    it.todo("should apply 20% loyalty discount for customers with 2+ years");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round premium up in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should return zero payout when damage is within deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to highly enchanted items (enchantment >= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should round payout down in MHPCO's favor");
  });
});

