function calculateItemPremiums(items: any[]): number {
  const mainItems = items.filter((i: any) => i.type in MAIN_ITEM_PREMIUMS);
  const components = items.filter((i: any) => !(i.type in MAIN_ITEM_PREMIUMS));

  const mainTotal = mainItems.reduce((sum: number, item: any) => sum + MAIN_ITEM_PREMIUMS[item.type], 0);

  const componentCounts: Record<string, number> = {};
