  const customer = scenario.customer;
  const results: any[] = [];
  let quoteCount = 0;

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const totalBasePremium = calculateItemPremiums(step.items);
      let adjustedPremium: number;
      if (quoteCount === 0) {
